onClick:
{{
(async () => {
  JSutils.resetInactivityTimer();

  const isInsert = appsmith.store.modalContexto?.acaoTipo === "ADICIONAR";
  const query = isInsert ? InsertPetAmigos : UpdatePetAmigos;

  const currentID = isInsert
    ? null
    : appsmith.store.amigoSelecionado?.amigo001_id;

  const params = {
    amigo001_ani002_id_amigo: Number(Select1Convivencia.selectedOptionValue),
    amigo001_observacao: (InputDescConvivencia.text || "").trim().toUpperCase(),
    amigo001_permitido: Switch1Convivencia.isSwitchedOn ? 'S' : 'N',
    amigo001_ani002_id_animal: Number(appsmith.store.petID_Amigos),
    amigo001_id: currentID
  };

  if (isInsert && !params.amigo001_ani002_id_amigo) {
    return showAlert("Selecione um animal para a convivência.", "warning");
  }

  try {
    const response = await query.run(params);

    const idParaSelecionar = isInsert
      ? response[0].amigo001_id
      : currentID;

    // 1. Atualiza lista
    await SelectAmigos.run();

    // 2. Define seleção (apenas via store)
    await storeValue('idSelecionadoAMIGO', idParaSelecionar);

    // 3. Atualiza registro selecionado (será sincronizado no onRowSelected)
    await storeValue('amigoSelecionado', {});

    // 4. Mantém modo edição
    await storeValue('modalContexto', {
      entidade: "AMIGO",
      acaoTipo: "EDITAR",
      acaoBotao: "ATUALIZAR"
    });

    showAlert(
      `Amigo ${isInsert ? 'incluído' : 'atualizado'} com sucesso!`,
      "success"
    );

  } catch (err) {
    showAlert("Erro ao salvar: " + err.message, "error");
  }
})()
}}
